previewCss:
.darma-loader-darma-custom-399 {color: var(--loader-color, #0f766e);
  --loader-secondary-color: #5eead4;
  --loader-bg: #ffffff;
  width: 52px;
  height: 92px;
  position: relative;
}.darma-loader-darma-custom-399:before,.darma-loader-darma-custom-399:after {content: "";
  position: absolute;
  inset: 0;
  background: var(--loader-color, #0f766e);
  box-shadow: 0 0 0 50px;
  clip-path: polygon(100% 0, 23% 46%, 46% 44%, 15% 69%, 38% 67%, 0 100%, 76% 57%, 53% 58%, 88% 33%, 60% 37%);
  ;
}.darma-loader-darma-custom-399:before {animation: darma-loader-darma-custom-399-l8 1s infinite;
  transform: perspective(300px) translateZ(0px)}@keyframes darma-loader-darma-custom-399-l8 {to {transform: perspective(300px) translateZ(180px);
  opacity:0}}

